    auto Hout = H - K + 1;
    auto Wout = W - K + 1;

    at::Tensor result = at::empty({N, Cout, Dout, Hout, Wout}, self.options());
    EXEC_NPU_CMD(aclnnConvStandard3dSquareInputSquareKernelCustom, self, weight, result);
    return result;
